import { Link } from 'react-router-dom';
import { ArrowRight, Globe, Gamepad2, Palette, CheckCircle, ChevronRight, Sparkles, Zap, Shield, Users, Code2, Layers, Star, Quote } from 'lucide-react';
import { useEffect, useRef, useState } from 'react';

/* ── Animated counter ── */
function Counter({ end, suffix = '' }) {
  const [v, setV] = useState(0); const ref = useRef(null); const started = useRef(false);
  useEffect(() => {
    const io = new IntersectionObserver(([e]) => {
      if (e.isIntersecting && !started.current) {
        started.current = true; let c = 0; const step = end / 60;
        const t = setInterval(() => { c += step; if (c >= end) { setV(end); clearInterval(t); } else setV(Math.floor(c)); }, 22);
      }
    }, { threshold: 0.4 });
    if (ref.current) io.observe(ref.current);
    return () => io.disconnect();
  }, [end]);
  return <span ref={ref}>{v}{suffix}</span>;
}

/* ── Fade-up on scroll ── */
function FadeUp({ children, delay = 0, style = {} }) {
  const ref = useRef(null); const [vis, setVis] = useState(false);
  useEffect(() => {
    const io = new IntersectionObserver(([e]) => { if (e.isIntersecting) setVis(true); }, { threshold: 0.12 });
    if (ref.current) io.observe(ref.current);
    return () => io.disconnect();
  }, []);
  return (
    <div ref={ref} style={{
      opacity: vis ? 1 : 0,
      transform: vis ? 'translateY(0)' : 'translateY(28px)',
      transition: `opacity 0.65s ${delay}s ease, transform 0.65s ${delay}s ease`,
      ...style,
    }}>{children}</div>
  );
}

const STACK = ['React', 'Node.js', 'Unity', 'Unreal Engine', 'AWS', 'Azure', 'Next.js', 'Docker', 'PostgreSQL', 'MongoDB', 'Python', 'TypeScript'];

const SERVICES = [
  { id: 'fullstack', Icon: Globe,    color: '#0057ff', title: 'Full Stack Development', desc: 'End-to-end web apps — from pixel-perfect frontends to scalable backends.', img: 'https://images.unsplash.com/photo-1461749280684-dccba630e2f6?w=700&q=80' },
  { id: 'gamedev',  Icon: Gamepad2,  color: '#7c3aed', title: 'Game Development',        desc: '2D & 3D games, mobile titles, and immersive interactive experiences.',     img: 'https://images.unsplash.com/photo-1593305841991-05c297ba4575?w=700&q=80' },
  { id: 'uiux',     Icon: Palette,   color: '#db2777', title: 'UI/UX Design',             desc: 'Interfaces that are intuitive, beautiful and conversion-focused.',         img: 'https://images.unsplash.com/photo-1561070791-2526d30994b5?w=700&q=80' },
];

const PROCESS = [
  { n: '01', icon: Sparkles, title: 'Discovery',    desc: 'We deep-dive into your goals, users, and market to define a clear product vision and technical roadmap.' },
  { n: '02', icon: Layers,   title: 'Architecture', desc: 'We design the system blueprint — scalable, secure, and optimised before a single line of code is written.' },
  { n: '03', icon: Code2,    title: 'Build',         desc: 'Agile sprints, weekly demos, and real-time updates keep you in the loop throughout every development cycle.' },
  { n: '04', icon: Zap,      title: 'Launch',        desc: 'Rigorous QA, automated deployment pipelines, and cloud launch — with zero downtime and full confidence.' },
  { n: '05', icon: Shield,   title: 'Support',       desc: 'Post-launch monitoring, performance tuning, and ongoing feature development to keep your product ahead.' },
];

const TESTIMONIALS = [
  { name: 'Rahul Menon',      role: 'Founder, TechStart',      stars: 5, text: 'Synnoviq delivered our SaaS platform in record time. Their full stack team is exceptional — the quality of code and design blew us away.' },
  { name: 'Ananya Krishnan',  role: 'Product Lead, GameForge',  stars: 5, text: 'Our Unity game went from concept to App Store in 4 months. The team\'s expertise in game mechanics and UI is truly world-class.' },
  { name: 'Vikram Patel',     role: 'CEO, FinServe App',        stars: 5, text: 'What impressed me most was how they treated our project as their own. Every milestone was hit, every feature polished to perfection.' },
];

const HIGHLIGHTS = [
  { Icon: Zap,    title: 'Fast Delivery',    desc: 'Agile sprints with weekly demos — we ship working software faster than traditional agencies.' },
  { Icon: Shield, title: 'NDA Protected',    desc: 'Full IP ownership and NDA on every project. Your idea stays yours — always.' },
  { Icon: Users,  title: 'Dedicated Teams',  desc: 'Cross-functional squads of developers, designers, and QA engineers on every project.' },
