                  onMouseLeave={e => { e.currentTarget.style.boxShadow = 'none'; e.currentTarget.style.transform = 'translateY(0)'; e.currentTarget.style.borderColor = 'var(--rule)'; }}
                >
                  <Quote size={28} style={{ color: 'var(--blue)', opacity: 0.3, marginBottom: 16 }} />
                  <p style={{ fontSize: '0.93rem', color: 'var(--ink60)', lineHeight: 1.8, flex: 1, marginBottom: 24, fontStyle: 'italic' }}>{t.text}</p>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                    <div style={{ width: 42, height: 42, borderRadius: '50%', background: 'var(--blue)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontFamily: 'var(--serif)', fontWeight: 800, color: '#fff', fontSize: '1rem', flexShrink: 0 }}>
                      {t.name[0]}
                    </div>
                    <div>
                      <strong style={{ display: 'block', fontSize: '0.9rem', color: 'var(--ink)', fontWeight: 700 }}>{t.name}</strong>
                      <span style={{ fontSize: '0.74rem', color: 'var(--ink20)' }}>{t.role}</span>
                    </div>
                    <div style={{ marginLeft: 'auto', display: 'flex', gap: 2 }}>
                      {[...Array(t.stars)].map((_, s) => <Star key={s} size={12} style={{ color: '#f59e0b', fill: '#f59e0b' }} />)}
                    </div>
                  </div>
                </div>
              </FadeUp>
            ))}
          </div>
        </div>
      </section>

      {/* ════════════════════════════════════════
          TECH STACK GRID
      ════════════════════════════════════════ */}
      <section style={{ background: 'var(--surf)', borderTop: '1px solid var(--rule)', borderBottom: '1px solid var(--rule)', padding: '52px 0' }}>
        <div className="wrap">
          <FadeUp>
            <p style={{ textAlign: 'center', fontSize: '0.7rem', fontWeight: 700, letterSpacing: '0.16em', textTransform: 'uppercase', color: 'var(--ink20)', marginBottom: 28 }}>Technologies We Master</p>
          </FadeUp>
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: 10, justifyContent: 'center' }}>
            {STACK.map((t, i) => (
              <FadeUp key={t} delay={i * 0.04}>
                <div style={{
                  padding: '10px 20px', borderRadius: 999,
                  background: 'var(--white)', border: '1px solid var(--rule)',
                  fontSize: '0.83rem', fontWeight: 600, color: 'var(--ink60)',
                  transition: 'all 0.2s ease', cursor: 'default',
                }}
                  onMouseEnter={e => { e.currentTarget.style.background = 'var(--blue)'; e.currentTarget.style.color = '#fff'; e.currentTarget.style.borderColor = 'var(--blue)'; e.currentTarget.style.transform = 'translateY(-2px)'; e.currentTarget.style.boxShadow = '0 6px 16px rgba(0,87,255,0.3)'; }}
                  onMouseLeave={e => { e.currentTarget.style.background = 'var(--white)'; e.currentTarget.style.color = 'var(--ink60)'; e.currentTarget.style.borderColor = 'var(--rule)'; e.currentTarget.style.transform = 'translateY(0)'; e.currentTarget.style.boxShadow = 'none'; }}
                >{t}</div>
              </FadeUp>
            ))}
          </div>
        </div>
      </section>

      {/* ════════════════════════════════════════
          INTERNSHIP CTA
      ════════════════════════════════════════ */}
      <section style={{ background: '#060c18', position: 'relative', overflow: 'hidden' }}>
        <img src="https://images.unsplash.com/photo-1523240795612-9a054b0db644?w=1600&q=75" alt="" aria-hidden style={{ position: 'absolute', inset: 0, width: '100%', height: '100%', objectFit: 'cover', opacity: .08 }} />
        <div style={{ position: 'absolute', inset: 0, background: 'linear-gradient(135deg,rgba(6,12,24,.97),rgba(0,35,100,.72))' }} />
        <div className="wrap" style={{ padding: '80px 20px', position: 'relative', zIndex: 1 }}>
          <div className="cta-row">
            <FadeUp style={{ maxWidth: 600 }}>
              <span style={{ fontSize: '0.68rem', fontWeight: 700, letterSpacing: '0.18em', textTransform: 'uppercase', color: 'rgba(255,255,255,0.4)', display: 'block', marginBottom: 10 }}>Internship Programme</span>
              <h2 className="t-h2 white" style={{ marginBottom: 12 }}>Shape Your Career with Synnoviq</h2>
              <p style={{ fontSize: '0.95rem', color: 'rgba(255,255,255,0.55)', lineHeight: 1.8 }}>Hands-on, mentor-driven internships tied to real live projects. If you're passionate about full stack, game dev, or design — we want to hear from you.</p>
            </FadeUp>
            <Link to="/careers#internships" style={{
              display: 'inline-flex', alignItems: 'center', gap: 8,
              padding: '14px 30px', borderRadius: 10, background: '#fff', color: 'var(--ink)',
              fontSize: '0.9rem', fontWeight: 700, flexShrink: 0,
              transition: 'all 0.2s', boxShadow: '0 4px 20px rgba(255,255,255,0.12)',
            }}
              onMouseEnter={e => { e.currentTarget.style.background = '#0057ff'; e.currentTarget.style.color = '#fff'; }}
              onMouseLeave={e => { e.currentTarget.style.background = '#fff'; e.currentTarget.style.color = 'var(--ink)'; }}
            >Apply Now <ArrowRight size={16} /></Link>
          </div>
        </div>
      </section>

      <style>{`
        @keyframes marquee { from { transform: translateX(0); } to { transform: translateX(-33.33%); } }
        @media (min-width: 768px) {
          .process-grid { grid-template-columns: 1fr 1fr !important; }
          .work-grid    { grid-template-columns: repeat(2,1fr) !important; }
          .g4-home      { grid-template-columns: repeat(4,1fr) !important; }
        }
        @media (min-width: 960px) {
          .work-grid { grid-template-columns: repeat(4,1fr) !important; }
          .work-grid > div > div { height: 280px !important; }
        }
      `}</style>
    </div>
  );
}
